        grid: &[Vec<i64>],
        m: usize,
        n: usize,
        i: usize,
        j: usize,
        visited: &mut Vec<Vec<bool>>,
        sum: i64,
        k: i64,
        mod_val: i64,
        hash: &mut std::collections::HashMap<i64, i64>,
        count: &mut i64,
    ) {
